import { useState } from "react";
import styled from "styled-components";

import backgroundImage from '../../img/ContactForm/bg.jpg'

import emailjs, { init } from 'emailjs-com';

const ContactForm = ({ id }) => {
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [message, setMessage] = useState('')
  const [contactFormErrors, setContactFormErrors] = useState({
    name: '', email: '', message: ''
  })

  const handleValidation = () => {
    let formIsValid = true
    let errors = { name: '', email: '', message: '' }

    if(name === '') {
      errors = { ...errors, name: "Please fill out this field." }
      formIsValid = false
    }

    if(email === '') {
      errors = { ...errors, email: "Please fill out this field." }
      formIsValid = false

    } else {
      let lastAtPos = email.lastIndexOf('@')
      let lastDotPos = email.lastIndexOf('.')

      if (lastAtPos === -1 || lastDotPos === -1) {
        errors = { ...errors, email: "Email is not valid." }
        formIsValid = false
      }
    }

    if(message.length < 5) {
      errors = { ...errors, message: "Message field must be atleast 5 characters long."}
      formIsValid = false
    }

    setContactFormErrors(errors)
    return formIsValid
  }

  const handleSubmit = (event) => {
    event.preventDefault()

    if(handleValidation()) {
      init("user_FokKGGu0nYvixQZZQCMYz")

      const params = {
        from_name: name,
        email: email,
        message: message
      };
  
      emailjs.send('service_e2649gi', 'template_8vmolpe', params)
        .then((response) => {
           console.log('SUCCESS!', response.status, response.text);
        }, (error) => {
           console.log('FAILED...', error);
        });
    }
  }

  return (
    <ContactFormContainer id={id}>
      <h3> Do you want to ask me a question? </h3>
      <h4> Use a contact form listed below </h4>

      <Form onSubmit={handleSubmit}>
        <InputGroup key={contactFormErrors.name}>
          <input
            type="text"
            placeholder="Name"
            value={name}
            onChange={({target}) => setName(target.value)} />
          <span> {contactFormErrors.name && contactFormErrors.name} </span>
        </InputGroup>
        <InputGroup key={contactFormErrors.email} >
          <input
            type="text"
            placeholder="Email Address"
            value={email}
            onChange={({target}) => setEmail(target.value)} />
          <span> {contactFormErrors.email && contactFormErrors.email} </span>
        </InputGroup>
        <InputGroup key={contactFormErrors.message}>
          <textarea
            placeholder="Message"
            value={message}
            onChange={({target}) => setMessage(target.value)} />
          <span> {contactFormErrors.message && contactFormErrors.message} </span>
        </InputGroup>
        <SubmitButton type="submit">
          Send a message
        </SubmitButton>
      </Form>
    </ContactFormContainer>
  )
}

const ContactFormContainer = styled.section`
  padding: 5em 0;
  background-size: cover;
  color: white;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  row-gap: 1em;
  box-shadow: 0px 0px 2px black;
  position: relative;
  
  &:before {
    content: "";
    position: absolute;
    z-index: -1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: url(${backgroundImage}) center center no-repeat;
    background-size: cover;
    filter: brightness(0.2) blur(4px);
    box-shadow: 0px 0px 1px black;
  }

  & h3 {
    margin: 0;
    font-size: 2em;
    text-align: center;
  }

  & h4 {
    margin: 0;
    font-size: 1em;
    font-weight: 400;
    text-align: center;
  }
`

const Form = styled.form`
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-top: 1em;
  row-gap: 1em;
  width: 50vw;
  max-width: 40em;

  & input, textarea {
    padding: 0.5em;
    font-family: Rubik;
    border-radius: 4px;
    box-shadow: 2px 2px 1px black;
    font-size: 1em;
    border: 0;
    width: 100%;
  }

  & textarea {
    min-width: 100%;
    max-width: 40em;
    min-height: 5em;
    max-height: 15em;
  }
`

const InputGroup = styled.div`
  width: 100%;
  display: flex;
  flex-direction: column;
  row-gap: 0.5em;

  & span {
    align-self: flex-start;
    height: 1em;
  }
`

const SubmitButton = styled.button`
  background: white;
  border: 0;
  color: black;
  border-radius: 4px;
  font-size: 1em;
  cursor: pointer;
  padding: 1em 2em;
  margin-top: 1em;
  font-family: Rubik;

  &:hover {
    box-shadow: 3px 3px 2px red;
  }
`

export default ContactForm
